function nQueens(data) {
    const n = parseInt(data);
    const results = [];
    const isSafe = (board, row, col) => {
        for (let i = 0; i < row; i++) {
            if (board[i] === col ||
            board[i] - i === col - row ||
            board[i] + i === col + row) {
                return false;
            }
        }
        return true;
    }
    ;
    const solveNQueens = (board, row) => {
        if (row === n) {
            const solution = board.map(col => '.'.repeat(col) + 'Q' + '.'.repeat(n - col - 1)).join('\n');
            results.push(solution);
            return;
        }
        for (let col = 0; col < n; col++) {
            if (isSafe(board, row, col)) {
                board[row] = col;
                solveNQueens(board, row + 1);
                board[row] = -1; // backtrack
            }
        }
    }
    ;
    solveNQueens(Array(n).fill(-1), 0);
    return results.join('\n\n');
}

