import java.util.ArrayList;
import java.util.List;
class Solution {
    public List<List<String>> nQueens(int data) {
        List<List<String>> results = new ArrayList<>();
        backtrack(new int[data], 0, results);
        return results;
    }
    private void backtrack(int[] queens, int row, List<List<String>> results) {
        if (row == queens.length) {
            results.add(constructBoard(queens));
            return;
        }
        for (int col = 0; col < queens.length; col++) {
            if (isValid(queens, row, col)) {
                queens[row] = col;
                backtrack(queens, row + 1, results);
            }
        }
    }
    private boolean isValid(int[] queens, int row, int col) {
        for (int i = 0; i < row; i++) {
            if (queens[i] == col ||
            queens[i] - i == col - row ||
            queens[i] + i == col + row) {
                return false;
            }
        }
        return true;
    }
    private List<String> constructBoard(int[] queens) {
        List<String> board = new ArrayList<>();
        for (int i = 0; i < queens.length; i++) {
            StringBuilder row = new StringBuilder();
            for (int j = 0; j < queens.length; j++) {
                if (j == queens[i]) {
                    row.append('Q');
                }
                else {
                    row.append('.');
                }
            }
            board.add(row.toString());
        }
        return board;
    }
}

