package main

import "fmt"

func nQueens(data int) [][]string {
    res := [][]string{}
    board := make([]string, data)
    for i := range board {
        board[i] = string(make([]rune, data))
        for j := range board[i] {
            board[i][j] = '.'
        }
    }
    solveNQueens(data, 0, board, &res)
    return res
}

func solveNQueens(n, row int, board []string, res *[][]string) {
    if row == n {
        temp := make([]string, n)
        copy(temp, board)
        *res = append(*res, temp)
        return
    }
    for col := 0; col < n; col++ {
        if isSafe(board, row, col, n) {
            board[row] = board[row][:col] + "Q" + board[row][col+1:]
            solveNQueens(n, row+1, board, res)
            board[row] = board[row][:col] + "." + board[row][col+1:]
        }
    }
}

func isSafe(board []string, row, col, n int) bool {
    for i := 0; i < row; i++ {
        if board[i][col] == 'Q' {
            return false
        }
        if col-(row-i) >= 0 && board[i][col-(row-i)] == 'Q' {
            return false
        }
        if col+(row-i) < n && board[i][col+(row-i)] == 'Q' {
            return false
        }
    }
    return true
}

func main() {
    result := nQueens(4)
    fmt.Println(result)
}

