using System.Collections.Generic;

public class Solution {
    public List<List<String>> nQueens(int data) {
        List<List<String>> result = new List<List<String>>();
        char[,] board = new char[data, data];
        for (int i = 0; i < data; i++) {
            for (int j = 0; j < data; j++) {
                board[i, j] = '.';
            }
        }
        SolveNQueens(result, board, 0, data);
        return result;
    }

    private void SolveNQueens(List<List<String>> result, char[,] board, int row, int n) {
        if (row == n) {
            List<String> solution = new List<String>();
            for (int i = 0; i < n; i++) {
                solution.Add(new string(board[i]));
            }
            result.Add(solution);
            return;
        }

        for (int col = 0; col < n; col++) {
            if (IsSafe(board, row, col, n)) {
                board[row, col] = 'Q';
                SolveNQueens(result, board, row + 1, n);
                board[row, col] = '.';
            }
        }
    }

    private bool IsSafe(char[,] board, int row, int col, int n) {
        for (int i = 0; i < row; i++) {
            if (board[i, col] == 'Q') return false;
            if (col - (row - i) >= 0 && board[i, col - (row - i)] == 'Q') return false;
            if (col + (row - i) < n && board[i, col + (row - i)] == 'Q') return false;
        }
        return true;
    }
}

