import java.util.ArrayList;
import java.util.List;
class Solution {
    public List<List<String>> nQueens(int data) {
        List<List<String>> result = new ArrayList<>();
        backtrack(result, new ArrayList<>(), data, 0);
        return result;
    }
    private void backtrack(List<List<String>> result, List<String> board, int n, int row) {
        if (row == n) {
            result.add(new ArrayList<>(board));
            return;
        }
        for (int col = 0; col < n; col++) {
            if (isSafe(board, row, col, n)) {
                StringBuilder sb = new StringBuilder();
                for (int i = 0; i < n; i++) {
                    if (i == col) sb.append('Q');
                    else sb.append('.');
                }
                board.add(sb.toString());
                backtrack(result, board, n, row + 1);
                board.remove(board.size() - 1);
            }
        }
    }
    private boolean isSafe(List<String> board, int row, int col, int n) {
        for (int i = 0; i < row; i++) {
            if (board.get(i).charAt(col) == 'Q') return false;
            if (col - (row - i) >= 0 && board.get(i).charAt(col - (row - i)) == 'Q') return false;
            if (col + (row - i) < n && board.get(i).charAt(col + (row - i)) == 'Q') return false;
        }
        return true;
    }
}

