using namespace std;
class Solution {
    public:
    vector<vector<string>> nQueens(int n) {
        vector<vector<string>> result;
        vector<string> board(n, string(n, '.'));
        vector<bool> cols(n, false), diag1(2 * n, false), diag2(2 * n, false);
        backtrack(result, board, 0, n, cols, diag1, diag2);
        return result;
    }
    private:
    void backtrack(vector<vector<string>>& result, vector<string>& board, int row, int n,
    vector<bool>& cols, vector<bool>& diag1, vector<bool>& diag2) {
        if (row == n) {
            result.push_back(board);
            return;
        }
        for (int col = 0; col < n; col++) {
            if (cols[col] || diag1[row + col] || diag2[row - col + n]) continue;
            board[row][col] = 'Q';
            cols[col] = diag1[row + col] = diag2[row - col + n] = true;
            backtrack(result, board, row + 1, n, cols, diag1, diag2);
            board[row][col] = '.';
            cols[col] = diag1[row + col] = diag2[row - col + n] = false;
        }
    }
}
